router = APIRouter(prefix="/evaluation", tags=["Evaluation"])

def send_notification_email(email_to: str, subject: str, body: str):
    # Simulated Async Email Sending with professional draft generated by open-source AI (Ollama)
    try:
        import llm_client
        prompt = (
            f"Draft a formal, highly professional business email notification for GeM (Government e-Marketplace) procurement.\n"
            f"To: {email_to}\n"
            f"Subject: {subject}\n"
            f"Body message summary: {body}\n\n"
            f"Ensure the email contains a formal greeting, detailed but concise information about the subject, and an appropriate professional sign-off from the GeM e-Marketplace Team."
        )
        drafted_email = llm_client.generate_text(prompt, temperature=0.3)
    except Exception:
        drafted_email = f"Subject: {subject}\n\n{body}"

    with open("email_logs.txt", "a", encoding="utf-8") as f:
        f.write(f"============================================================\n")
        f.write(f"[{datetime.utcnow().isoformat()}] EMAIL TO {email_to} | SUBJ: {subject}\n")
        f.write(f"------------------------------------------------------------\n")
        f.write(drafted_email.strip())
        f.write(f"\n============================================================\n\n")

def recalculate_ranks(db: Session, tender_id: int):
    """Recalculate composite scores and ranks for all bids in a tender."""
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender:
        return
    bids = db.query(models.Bid).filter(
        models.Bid.tender_id == tender_id,
        models.Bid.is_disqualified.is_(False)
    ).all()

    tech_w = tender.technical_weightage / 100.0
    fin_w = tender.financial_weightage / 100.0

    # Financial score: L1 method (lowest bid gets 100)
    amounts = [b.total_amount for b in bids if b.total_amount and b.total_amount > 0]
    min_amount = min(amounts) if amounts else 1

    tech_criteria = [c for c in tender.criteria if c.criteria_type == "Technical"]
    scores_by_bid = {b.id: [] for b in bids}
    if tech_criteria and bids:
        all_scores = db.query(models.BidScore).filter(
            models.BidScore.bid_id.in_([b.id for b in bids]),
            models.BidScore.criteria_id.in_([c.id for c in tech_criteria])
        ).all()
        for s in all_scores:
            scores_by_bid[s.bid_id].append(s)

    for bid in bids:
        # Technical score from criteria
        tech_score = 0.0
        if tech_criteria:
            scores = scores_by_bid.get(bid.id, [])
            total_weight = sum(c.weight for c in tech_criteria)
            weighted_score = sum(
                (s.score / next((c.max_score for c in tech_criteria if c.id == s.criteria_id), 100)) * 100
                * (next((c.weight for c in tech_criteria if c.id == s.criteria_id), 0) / total_weight)
                for s in scores
            ) if total_weight > 0 else 0
            tech_score = weighted_score

        max_score_sum = sum(c.max_score for c in tech_criteria) if tech_criteria else 100
        tech_pct = (tech_score / max_score_sum) * 100 if max_score_sum else 0
        
        threshold = getattr(tender, 'technical_threshold', 70.0)
        if tech_pct < threshold:
            bid.is_disqualified = True
            bid.disqualification_reason = "Failed Technical Threshold"
            bid.financial_score = 0
            bid.composite_score = 0
            bid.evaluated_at = datetime.utcnow()
            continue

        # Financial score: L1 method
        fin_score = (min_amount / bid.total_amount * 100) if bid.total_amount else 0

        bid.technical_score = round(tech_score, 2)
        bid.financial_score = round(fin_score, 2)
        bid.composite_score = round(tech_score * tech_w + fin_score * fin_w, 2)
        bid.evaluated_at = datetime.utcnow()

    # Rank by composite score descending
    ranked = sorted([b for b in bids if not b.is_disqualified], key=lambda b: b.composite_score, reverse=True)
    for i, bid in enumerate(ranked, start=1):
        bid.rank = i

    db.commit()


@router.post("/score")
def score_bid(evaluation: schemas.BidEvaluationInput,
              db: Session = Depends(get_db),
              current_user=Depends(auth.require_role("Admin", "Evaluator"))):
    bid = db.query(models.Bid).filter(models.Bid.id == evaluation.bid_id).first()
    if not bid:
        raise HTTPException(status_code=404, detail="Bid not found")

    tender = db.query(models.Tender).filter(models.Tender.id == bid.tender_id).first()

    if evaluation.is_disqualified:
        bid.is_disqualified = True
        bid.disqualification_reason = evaluation.disqualification_reason
        bid.status = "Disqualified"
        db.commit()
        recalculate_ranks(db, bid.tender_id)
        return {
            "message": "Bid disqualified",
            "bid_id": bid.id,
            "vendor_name": bid.vendor.company_name if bid.vendor else "N/A",
            "is_disqualified": True,
            "disqualification_reason": evaluation.disqualification_reason,
            "technical_score": 0,
            "financial_score": 0,
            "composite_score": 0,
            "rank": None,
            "criteria_detail": []
        }

    # Upsert scores
    for score_input in evaluation.scores:
        existing = db.query(models.BidScore).filter(
            models.BidScore.bid_id == evaluation.bid_id,
            models.BidScore.criteria_id == score_input.criteria_id
        ).first()
        if existing:
            existing.score = score_input.score
            existing.remarks = score_input.remarks
            existing.evaluated_by = current_user.id
        else:
            new_score = models.BidScore(
                bid_id=evaluation.bid_id,
                criteria_id=score_input.criteria_id,
                score=score_input.score,
                remarks=score_input.remarks,
                evaluated_by=current_user.id
            )
            db.add(new_score)

    bid.status = "Evaluated"
    db.commit()
    recalculate_ranks(db, bid.tender_id)
    db.refresh(bid)

    # Build detailed per-criteria result
    tech_criteria = db.query(models.EvaluationCriteria).filter(
        models.EvaluationCriteria.tender_id == bid.tender_id,
        models.EvaluationCriteria.criteria_type == "Technical"
    ).all()
    all_scores = db.query(models.BidScore).filter(
        models.BidScore.bid_id == bid.id
    ).all()
    score_map = {s.criteria_id: s for s in all_scores}
    total_weight = sum(c.weight for c in tech_criteria) if tech_criteria else 1
    threshold = getattr(tender, 'technical_threshold', 70.0)

    criteria_detail = []
    for c in tech_criteria:
        s = score_map.get(c.id)
        raw = s.score if s else 0
        pct = round((raw / c.max_score) * 100, 2) if c.max_score else 0
        weighted_contribution = round((raw / c.max_score) * (c.weight / total_weight) * 100, 2) if c.max_score and total_weight else 0
        criteria_detail.append({
            "criteria_id": c.id,
            "criteria_name": c.name,
            "raw_score": raw,
            "max_score": c.max_score,
            "score_pct": pct,
            "weight": c.weight,
            "weight_pct": round((c.weight / total_weight) * 100, 1) if total_weight else 0,
            "weighted_contribution": weighted_contribution,
            "remarks": s.remarks if s else "",
            "pass": pct >= threshold
        })

    # Financial score calculation details
    bids_same_tender = db.query(models.Bid).filter(
        models.Bid.tender_id == bid.tender_id,
        models.Bid.is_disqualified.is_(False)
    ).all()
    amounts = [b.total_amount for b in bids_same_tender if b.total_amount and b.total_amount > 0]
    min_amount = min(amounts) if amounts else 1

    return {
        "message": "Bid scored successfully",
        "bid_id": bid.id,
        "vendor_name": bid.vendor.company_name if bid.vendor else "N/A",
        "is_disqualified": bid.is_disqualified,
        "disqualification_reason": bid.disqualification_reason,
        "technical_score": round(bid.technical_score, 2),
        "financial_score": round(bid.financial_score, 2),
        "composite_score": round(bid.composite_score, 2),
        "rank": bid.rank,
        "tech_weightage": tender.technical_weightage if tender else 70,
        "fin_weightage": tender.financial_weightage if tender else 30,
        "technical_threshold": threshold,
        "passed_threshold": not bid.is_disqualified,
        "l1_amount": min_amount,
        "bid_amount": bid.total_amount,
        "financial_score_formula": f"L1/Bid × 100 = {min_amount:,.0f}/{bid.total_amount:,.0f} × 100 = {bid.financial_score:.2f}",
        "composite_formula": f"Tech×{tender.technical_weightage/100} + Fin×{tender.financial_weightage/100} = {bid.technical_score:.2f}×{tender.technical_weightage/100:.2f} + {bid.financial_score:.2f}×{tender.financial_weightage/100:.2f} = {bid.composite_score:.2f}",
        "criteria_detail": criteria_detail
    }


@router.post("/award/{tender_id}/{bid_id}")
def award_tender(tender_id: int, bid_id: int, background_tasks: BackgroundTasks, db: Session = Depends(get_db),
                 current_user=Depends(auth.require_role("Admin"))):
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender:
        raise HTTPException(status_code=404, detail="Tender not found")
    bid = db.query(models.Bid).filter(
        models.Bid.id == bid_id,
        models.Bid.tender_id == tender_id
    ).first()
    if not bid:
        raise HTTPException(status_code=404, detail="Bid not found")

    tender.status = "Awarded"
    bid.status = "Awarded"
    
    # Trigger async email
    vendor_email = bid.vendor.email if bid.vendor and bid.vendor.email else "vendor@example.com"
    background_tasks.add_task(
        send_notification_email, 
        vendor_email, 
        f"Contract Awarded: {tender.bid_number}", 
        f"Congratulations! Your bid for {tender.title} has been awarded."
    )
    
    db.commit()
    
    # Generate Web3 Solidity Smart Contract using open-source AI (Ollama) dynamically
    os.makedirs("contracts", exist_ok=True)
    safe_bid_number = tender.bid_number.replace('/', '_').replace('-', '_')
    contract_name = safe_bid_number
    
    vendor_name_clean = bid.vendor.company_name if bid.vendor else 'N/A'
    gem_reg_no_clean = bid.vendor.gem_reg_no if bid.vendor else 'N/A'
    award_amt_clean = int(bid.total_amount)
    delivery_days_clean = getattr(bid, 'delivery_period', 0)
    
    prompt = (
        f"Generate a secure, gas-optimized Solidity smart contract for a Government of India (GeM) tender award.\n"
        f"Tender Details:\n"
        f"- Bid Number / Contract Name: GEM_{contract_name}\n"
        f"- Vendor Name: {vendor_name_clean}\n"
        f"- GeM Registration Number: {gem_reg_no_clean}\n"
        f"- Award Amount (INR): {award_amt_clean} Rupees\n"
        f"- Delivery Period (Days): {delivery_days_clean}\n\n"
        f"The smart contract should include standard functions like constructor setting the government admin, marking completion, event logging for ContractAwarded and ContractCompleted, and proper security modifiers.\n"
        f"Return ONLY the valid Solidity source code. Do NOT wrap it in markdown code blocks or write any introduction/explanation. Start with '// SPDX-License-Identifier: MIT'."
    )
    
    try:
        import llm_client
        generated_code = llm_client.generate_text(prompt, temperature=0.1)
        # clean code fences if any
        cleaned_code = generated_code.strip()
        if cleaned_code.startswith("```"):
            lines = cleaned_code.splitlines()
            if lines[0].startswith("```"):
                lines = lines[1:]
            if lines[-1].strip() == "```":
                lines = lines[:-1]
            cleaned_code = "\n".join(lines).strip()
        if "contract" in cleaned_code and "pragma solidity" in cleaned_code:
            contract_code = cleaned_code
        else:
            raise ValueError("Invalid Solidity structure returned by LLM")
    except Exception as e:
        # Fallback to standard robust contract template if LLM is unavailable
        contract_code = f"""// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

/**
 * @title GEM Procurement Smart Contract
 * @dev Autogenerated by GEM AI Engine (Fallback)
 */
contract GEM_{contract_name} {{
    address public governmentAdmin;
    string public vendorName;
    string public gemRegistrationNumber;
    uint256 public awardAmountINR;
    uint256 public deliveryPeriodDays;
    bool public isCompleted;

    event ContractAwarded(string vendor, uint256 amount);
    event ContractCompleted();

    constructor() {{
        governmentAdmin = msg.sender;
        vendorName = "{vendor_name_clean}";
        gemRegistrationNumber = "{gem_reg_no_clean}";
        awardAmountINR = {award_amt_clean};
        deliveryPeriodDays = {delivery_days_clean};
        isCompleted = false;
        
        emit ContractAwarded(vendorName, awardAmountINR);
    }}

    function markCompleted() public {{
        require(msg.sender == governmentAdmin, "Only authorized Admin can complete");
        isCompleted = true;
        emit ContractCompleted();
    }}
}}
"""
    with open(f"contracts/{safe_bid_number}.sol", "w", encoding="utf-8") as f:
        f.write(contract_code)
    
    blockchain.create_audit_log(db, current_user.id, "AWARD_TENDER", "Tender", tender_id, f"Awarded to Bid {bid_id}")
    db.commit()
    return {"message": "Tender Awarded and Web3 Smart Contract Generated"}


@router.get("/contract/{tender_id}/{bid_id}")
def download_contract(tender_id: int, bid_id: int, db: Session = Depends(get_db)):
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    bid = db.query(models.Bid).filter(models.Bid.id == bid_id).first()
    if not tender or not bid:
        raise HTTPException(status_code=404, detail="Not found")
        
    tender_data = {"bid_number": tender.bid_number, "title": tender.title}
    vendor_data = {"company_name": bid.vendor.company_name if bid.vendor else "N/A", "gem_reg_no": bid.vendor.gem_reg_no if bid.vendor else "N/A"}
    
    pdf_buffer = pdf_generator.generate_contract_pdf(tender_data, vendor_data, bid.total_amount)
    
    return StreamingResponse(
        pdf_buffer,
        media_type="application/pdf",
        headers={"Content-Disposition": f"attachment; filename=Contract_{tender.bid_number}.pdf"}
    )

@router.get("/smart-contract/{tender_id}")
def download_smart_contract(tender_id: int, db: Session = Depends(get_db)):
    """Downloads the generated Web3 Solidity Smart Contract"""
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender or tender.status != "Awarded":
        raise HTTPException(status_code=404, detail="Contract not generated yet")
        
    safe_bid_number = tender.bid_number.replace('/', '_').replace('-', '_')
    file_path = f"contracts/{safe_bid_number}.sol"
    if not os.path.exists(file_path):
        raise HTTPException(status_code=404, detail="Smart contract file missing")
        
    return FileResponse(file_path, media_type='text/plain', filename=f"{safe_bid_number}_Web3.sol")

@router.get("/comparative/{tender_id}")
def comparative_statement(tender_id: int, db: Session = Depends(get_db),
                          current_user=Depends(auth.get_current_user)):
    """
    Comparative Statement for a tender.

    Data source priority:
      1. Real database bids (models.Bid) - always preferred
      2. PQC folder data - only used as fallback when no DB bids exist
         (useful for the Haldia Refinery demo tender with folder-based vendors)
    """
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender:
        raise HTTPException(status_code=404, detail="Tender not found")

    from sqlalchemy.orm import joinedload
    tech_w = tender.technical_weightage / 100.0
    fin_w = tender.financial_weightage / 100.0
    threshold = getattr(tender, "technical_threshold", 70.0)

    # Strategy 1: Use REAL database bids
    db_bids = (
        db.query(models.Bid)
        .options(joinedload(models.Bid.vendor), joinedload(models.Bid.scores))
        .filter(models.Bid.tender_id == tender_id)
        .all()
    )

    if db_bids:
        qualified_db = [b for b in db_bids if not b.is_disqualified and b.total_amount and b.total_amount > 0]
        amounts = [b.total_amount for b in qualified_db]
        l1_amount = min(amounts) if amounts else 0

        raw_bids = []
        for b in db_bids:
            v = b.vendor
            if not b.is_disqualified and b.total_amount and l1_amount:
                fin_score = round((l1_amount / b.total_amount) * 100, 2)
            else:
                fin_score = 0.0

            composite = round(b.technical_score * tech_w + fin_score * fin_w, 2) if not b.is_disqualified else 0.0

            criteria_list = db.query(models.EvaluationCriteria).filter(
                models.EvaluationCriteria.tender_id == tender_id,
                models.EvaluationCriteria.criteria_type == "Technical"
            ).all()
            score_map = {s.criteria_id: s for s in b.scores}
            total_weight = sum(c.weight for c in criteria_list) if criteria_list else 1

            criteria_breakdown = []
            for c in criteria_list:
                s = score_map.get(c.id)
                raw = s.score if s else 0.0
                pct = round((raw / c.max_score) * 100, 2) if c.max_score else 0
                criteria_breakdown.append({
                    "criteria_id": c.id, "name": c.name,
                    "raw_score": raw, "max_score": c.max_score, "score_pct": pct,
                    "weight": c.weight, "weight_pct": round((c.weight / total_weight) * 100, 1),
                    "weighted_contribution": round((raw / c.max_score) * (c.weight / total_weight) * 100, 2) if c.max_score else 0,
                    "remarks": s.remarks if s else "",
                    "pass": pct >= threshold,
                })

            fin_formula = (
                f"({l1_amount:,.0f} / {b.total_amount:,.0f}) x 100 = {fin_score:.2f}"
                if b.total_amount and l1_amount else ""
            )
            composite_formula = (
                f"{b.technical_score:.2f}x{tech_w:.2f} + {fin_score:.2f}x{fin_w:.2f} = {composite:.2f}"
            )

            raw_bids.append({
                "id": b.id, "rank": b.rank,
                "vendor_name": v.company_name if v else f"Vendor {b.vendor_id}",
                "gem_reg_no": v.gem_reg_no if v else "N/A",
                "msme": v.msme if v else False,
                "make_in_india": v.make_in_india if v else False,
                "bid_amount": b.bid_amount, "taxes": b.taxes, "total_amount": b.total_amount,
                "technical_score": b.technical_score, "financial_score": fin_score,
                "composite_score": composite, "composite_esg_score": getattr(b, "composite_esg_score", 0.0), "is_disqualified": b.is_disqualified,
                "disqualification_reason": b.disqualification_reason, "status": b.status,
                "evaluated_at": b.evaluated_at.isoformat() if b.evaluated_at else datetime.utcnow().isoformat(),
                "criteria_scores": {s.criteria_id: s.score for s in b.scores},
                "criteria_breakdown": criteria_breakdown,
                "fin_score_formula": fin_formula, "composite_formula": composite_formula,
                "l1_amount": l1_amount,
                "savings_vs_l1": round(b.total_amount - l1_amount, 2) if b.total_amount else 0,
            })

        raw_bids.sort(key=lambda x: (x["is_disqualified"], x["rank"] if x["rank"] else 999, x["vendor_name"]))
        criteria_list = db.query(models.EvaluationCriteria).filter(models.EvaluationCriteria.tender_id == tender_id).all()

        return {
            "tender": {
                "id": tender.id, "bid_number": tender.bid_number, "title": tender.title,
                "department": tender.department, "estimated_value": tender.estimated_value,
                "technical_weightage": tender.technical_weightage,
                "financial_weightage": tender.financial_weightage,
                "technical_threshold": threshold,
                "is_financial_opened": tender.is_financial_opened,
                "is_auction_active": tender.is_auction_active,
            },
            "criteria": [{"id": c.id, "name": c.name, "criteria_type": c.criteria_type,
                          "weight": c.weight, "max_score": c.max_score} for c in criteria_list],
            "bids": raw_bids, "data_source": "database",
            "scoring_legend": {
                "technical_method": "Weighted sum of per-criteria scores, normalised to 100",
                "financial_method": "L1 Method: (L1_amount / Bid_amount) x 100",
                "composite_method": f"Tech_Score x {tech_w:.2f} + Fin_Score x {fin_w:.2f}",
                "disqualification_rule": f"Bids scoring below {threshold}% on Technical are automatically disqualified",
            },
        }

    # Strategy 2: Fallback to PQC folder data (demo/Haldia tender only)
    from routers.reports import get_pqc_comparison_data
    import hashlib

    pqc_data = get_pqc_comparison_data()
    vendors = pqc_data.get("vendors", [])

    # Use the tender's actual estimated_value as the base for all bid amounts.
    # Qualified bids are priced 80–95% of estimate; disqualified bids 100–115%.
    # This ensures amounts are always proportional to the real tender — no magic numbers.
    base_value = tender.estimated_value or pqc_data.get("estimated_value") or 5_000_000

    qualified_list = sorted([v for v in vendors if v["status"] == "Accepted"], key=lambda x: x["name"])
    disqualified_list = sorted([v for v in vendors if v["status"] == "Rejected"], key=lambda x: x["name"])

    raw_bids = []
    for q_idx, v in enumerate(qualified_list):
        h = int(hashlib.sha256(v["name"].encode("utf-8")).hexdigest(), 16)
        # Spread qualified bids between 80%–95% of estimated value, deterministically
        spread_pct = 0.80 + (h % 150) / 1000.0  # 0.80 – 0.95, deterministic per vendor
        bid_amount = round(base_value * spread_pct, -3)  # round to nearest thousand
        raw_bids.append({
            "id": q_idx + 100, "vendor_name": v["name"],
            "gem_reg_no": f"GEM/V/{(h % 900000) + 100000}",
            "msme": v["has_maf"], "make_in_india": v["has_annexure"],
            "bid_amount": bid_amount, "taxes": round(bid_amount * 0.18, 2), "total_amount": bid_amount,
            "technical_score": v["risk_profile"]["technical"], "is_disqualified": False,
            "disqualification_reason": v["verdict_reason"], "status": "Evaluated",
        })

    for d_idx, v in enumerate(disqualified_list):
        h = int(hashlib.sha256(v["name"].encode("utf-8")).hexdigest(), 16)
        # Disqualified bids are priced 100%–115% of estimate (above budget)
        spread_pct = 1.00 + (h % 150) / 1000.0  # 1.00 – 1.15, deterministic per vendor
        bid_amount = round(base_value * spread_pct, -3)
        raw_bids.append({
            "id": d_idx + 200, "vendor_name": v["name"],
            "gem_reg_no": f"GEM/V/{(h % 900000) + 100000}",
            "msme": v["has_maf"], "make_in_india": v["has_annexure"],
            "bid_amount": bid_amount, "taxes": round(bid_amount * 0.18, 2), "total_amount": bid_amount,
            "technical_score": v["risk_profile"]["technical"], "is_disqualified": True,
            "disqualification_reason": v["verdict_reason"], "status": "Disqualified",
        })

    qualified_amounts = [b["total_amount"] for b in raw_bids if not b["is_disqualified"] and b["total_amount"] > 0]
    l1_amount = min(qualified_amounts) if qualified_amounts else 0

    for b in raw_bids:
        if b["is_disqualified"]:
            b["financial_score"] = 0.0; b["composite_score"] = 0.0; b["rank"] = None
        else:
            fin_score = (l1_amount / b["total_amount"] * 100) if b["total_amount"] else 0.0
            b["financial_score"] = round(fin_score, 2)
            b["composite_score"] = round(b["technical_score"] * tech_w + fin_score * fin_w, 2)

    ranked = sorted([b for b in raw_bids if not b["is_disqualified"]], key=lambda x: x["composite_score"], reverse=True)
    rank_map = {b["vendor_name"]: r for r, b in enumerate(ranked, start=1)}
    for b in raw_bids:
        b["rank"] = rank_map.get(b["vendor_name"])
        b["criteria_breakdown"] = [{
            "criteria_id": 1, "name": "Technical Evaluation Checklist",
            "raw_score": b["technical_score"], "max_score": 100.0,
            "score_pct": b["technical_score"], "weight": 70.0, "weight_pct": 70.0,
            "weighted_contribution": round(b["technical_score"] * 0.7, 2),
            "remarks": "PQC folder checklist validation.", "pass": b["technical_score"] >= threshold,
        }]
        b["fin_score_formula"] = f"({l1_amount:,.0f} / {b['total_amount']:,.0f}) x 100 = {b['financial_score']:.2f}" if b["total_amount"] and l1_amount else ""
        b["composite_formula"] = f"{b['technical_score']:.2f}x{tech_w:.2f} + {b['financial_score']:.2f}x{fin_w:.2f} = {b['composite_score']:.2f}"
        b["evaluated_at"] = datetime.utcnow().isoformat()
        b["criteria_scores"] = {1: b["technical_score"]}
        b["l1_amount"] = l1_amount
        b["savings_vs_l1"] = round(b["total_amount"] - l1_amount, 2) if b["total_amount"] else 0

    raw_bids.sort(key=lambda x: (x["is_disqualified"], x["rank"] if x["rank"] is not None else 999, x["vendor_name"]))

    return {
        "tender": {
            "id": tender.id, "bid_number": tender.bid_number, "title": tender.title,
            "department": tender.department, "estimated_value": tender.estimated_value,
            "technical_weightage": tender.technical_weightage,
            "financial_weightage": tender.financial_weightage,
            "technical_threshold": threshold, "is_financial_opened": True, "is_auction_active": False,
        },
        "criteria": [], "bids": raw_bids, "data_source": "pqc_folders",
        "scoring_legend": {
            "technical_method": "Weighted sum of per-criteria scores, normalised to 100",
            "financial_method": "L1 Method: (L1_amount / Bid_amount) x 100",
            "composite_method": f"Tech_Score x {tech_w:.2f} + Fin_Score x {fin_w:.2f}",
            "disqualification_rule": f"Bids scoring below {threshold}% on Technical are automatically disqualified",
        },
    }

