from pydantic import BaseModel
class AuctionBidInput(BaseModel):
    amount: float

@router.post("/auction/start/{tender_id}")
def start_reverse_auction(tender_id: int, db: Session = Depends(get_db), current_user=Depends(auth.require_role("Admin"))):
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender:
        raise HTTPException(status_code=404, detail="Tender not found")
        
    if not tender.is_financial_opened:
        raise HTTPException(status_code=400, detail="Financial bids must be opened first")
        
    tender.is_auction_active = True
    tender.auction_end_time = datetime.utcnow() + timedelta(minutes=10)
    blockchain.create_audit_log(db, current_user.id, "AUCTION_START", "Tender", tender_id, "Live Reverse Auction Started")
    db.commit()
    return {"message": "Reverse Auction Started successfully", "end_time": tender.auction_end_time}

@router.get("/auction/{tender_id}")
def get_auction_state(tender_id: int, db: Session = Depends(get_db)):
    tender = db.query(models.Tender).filter(models.Tender.id == tender_id).first()
    if not tender:
        raise HTTPException(status_code=404, detail="Tender not found")
        
    bids = db.query(models.Bid).filter(
        models.Bid.tender_id == tender_id,
        models.Bid.is_disqualified.is_(False)
    ).all()
    
